 11→/**
 12→ * Find all text matches within a container, returning Range objects.
 13→ */
 14→function findMatches(container: HTMLElement, query: string): Range[] {
 15→  if (!query) return [];
 16→
 17→  const lowerQuery = query.toLowerCase();
 18→  const ranges: Range[] = [];
 19→  const walker = document.createTreeWalker(
 20→    container,
 21→    NodeFilter.SHOW_TEXT,
 22→    null
 23→  );
 24→
 25→  let node: Text | null;
 26→  while ((node = walker.nextNode() as Text | null)) {
 27→    const text = (node.textContent ?? "").toLowerCase();
 28→    let idx = 0;
 29→    while (idx < text.length) {
 30→      const found = text.indexOf(lowerQuery, idx);
 31→      if (found === -1) break;
 32→
 33→      const range = document.createRange();
 34→      range.setStart(node, found);
 35→      range.setEnd(node, found + query.length);
 36→      ranges.push(range);
 37→
 38→      idx = found + lowerQuery.length;
 39→    }
 40→  }
 41→
 42→  return ranges;
 43→}
 44→
 45→/**
 46→ * Navigate to a match by selecting its Range and scrolling into view.
 47→ */
 48→function navigateToMatch(matches: Range[], index: number) {
 49→  if (index < 0 || index >= matches.length) return;
 50→
 51→  const sel = window.getSelection();
 52→  if (!sel) return;
 53→
 54→  sel.removeAllRanges();
 55→  sel.addRange(matches[index]);
