 61→export function SearchableContainer({
 62→  isSearchOpen,
 63→  onClose,
 64→  children,
 65→  className,
 66→}: SearchableContainerProps) {
 67→  const contentRef = useRef<HTMLDivElement>(null);
 68→  const [query, setQuery] = useState("");
 69→  const [matches, setMatches] = useState<Range[]>([]);
 70→  const [currentIndex, setCurrentIndex] = useState(0);
 71→  const debounceRef = useRef<ReturnType<typeof setTimeout>>(undefined);
 72→
 73→  // Find and count matches when query changes (don't navigate — that steals focus)
 74→  useEffect(() => {
 75→    clearTimeout(debounceRef.current);
 76→
 77→    if (!query || !contentRef.current) {
 78→      setMatches([]);
 79→      setCurrentIndex(0);
 80→      return;
 81→    }
 82→
 83→    debounceRef.current = setTimeout(() => {
 84→      if (!contentRef.current) return;
 85→      const found = findMatches(contentRef.current, query);
 86→      setMatches(found);
 87→      setCurrentIndex(found.length > 0 ? 1 : 0);
 88→    }, 150);
 89→
 90→    return () => clearTimeout(debounceRef.current);
 91→  }, [query]);
 92→
 93→  const handleNext = useCallback(() => {
 94→    if (matches.length === 0) return;
 95→    const next = currentIndex >= matches.length ? 1 : currentIndex + 1;
 96→    setCurrentIndex(next);
 97→    navigateToMatch(matches, next - 1);
 98→  }, [matches, currentIndex]);
 99→
100→  const handlePrevious = useCallback(() => {
101→    if (matches.length === 0) return;
102→    const prev = currentIndex <= 1 ? matches.length : currentIndex - 1;
103→    setCurrentIndex(prev);
104→    navigateToMatch(matches, prev - 1);
105→  }, [matches, currentIndex]);
106→
107→  const handleClose = useCallback(() => {
108→    setQuery("");
109→    setMatches([]);
110→    setCurrentIndex(0);
111→    window.getSelection()?.removeAllRanges();
112→    onClose();
113→  }, [onClose]);
114→
115→  // Reset on close
116→  useEffect(() => {
117→    if (!isSearchOpen) {
118→      setQuery("");
119→      setMatches([]);
120→      setCurrentIndex(0);
121→      window.getSelection()?.removeAllRanges();
122→    }
123→  }, [isSearchOpen]);
124→
125→  return (
126→    <div className={`relative ${className ?? ""}`}>
127→      {isSearchOpen && (
128→        <div className="absolute right-0 top-0 z-20">
129→          <FindBar
130→            query={query}
131→            onQueryChange={setQuery}
132→            currentMatch={currentIndex}
133→            totalMatches={matches.length}
134→            onNext={handleNext}
135→            onPrevious={handlePrevious}
136→            onClose={handleClose}
137→          />
138→        </div>
139→      )}
140→      <div ref={contentRef} className="contents">
141→        {children}
142→      </div>
143→    </div>
144→  );
145→}
