285→/// Global Ghostty application instance. One per process.
286→pub struct GhosttyApp {
287→    inner: *mut c_void,
288→}
289→
290→// SAFETY: GhosttyApp is only accessed through Mutex<GhosttyState>
291→unsafe impl Send for GhosttyApp {}
292→unsafe impl Sync for GhosttyApp {}
293→
294→#[allow(dead_code)]
295→impl GhosttyApp {
296→    /// Initialize libghostty and create the app with the user's default config.
297→    pub fn new() -> Result<Self, String> {
298→        unsafe {
299→            // Initialize the library
300→            let ret = ghostty_init(0, ptr::null_mut());
301→            if ret != 0 {
302→                return Err(format!("ghostty_init failed with code {}", ret));
303→            }
304→
305→            // Create and load config (reads ~/.config/ghostty/config automatically)
306→            let config = ghostty_config_new();
307→            if config.is_null() {
308→                return Err("ghostty_config_new returned null".into());
309→            }
310→            ghostty_config_load_default_files(config);
311→            ghostty_config_finalize(config);
312→
313→            // Set up runtime callbacks
314→            let runtime_config = GhosttyRuntimeConfig {
315→                userdata: ptr::null_mut(),
316→                supports_selection_clipboard: true,
317→                wakeup_cb: runtime_wakeup,
318→                action_cb: runtime_action,
319→                read_clipboard_cb: runtime_read_clipboard,
320→                confirm_read_clipboard_cb: runtime_confirm_read_clipboard,
321→                write_clipboard_cb: runtime_write_clipboard,
322→                close_surface_cb: runtime_close_surface,
323→            };
324→
325→            let app = ghostty_app_new(&runtime_config, config);
326→            if app.is_null() {
327→                ghostty_config_free(config);
328→                return Err("ghostty_app_new returned null".into());
329→            }
330→
331→            Ok(Self { inner: app })
332→        }
333→    }
334→
335→    /// Pump the ghostty event loop. Call from a timer or run loop.
336→    pub fn tick(&self) {
337→        unsafe { ghostty_app_tick(self.inner) }
338→    }
339→
340→    pub fn set_focus(&self, focused: bool) {
341→        unsafe { ghostty_app_set_focus(self.inner, focused) }
342→    }
343→
344→    pub fn raw(&self) -> *mut c_void {
345→        self.inner
346→    }
347→}
348→
349→impl Drop for GhosttyApp {
350→    fn drop(&mut self) {
351→        if !self.inner.is_null() {
352→            unsafe { ghostty_app_free(self.inner) };
353→        }
354→    }
355→}
