560→/// Get the raw NSWindow pointer from a Tauri webview window.
561→pub fn get_nswindow(window: &tauri::WebviewWindow) -> Result<*mut c_void, String> {
562→    #[cfg(target_os = "macos")]
563→    {
564→        use raw_window_handle::{HasWindowHandle, RawWindowHandle};
565→
566→        let handle = window
567→            .window_handle()
568→            .map_err(|e| format!("Failed to get window handle: {}", e))?;
569→
570→        match handle.as_raw() {
571→            RawWindowHandle::AppKit(handle) => {
572→                // ns_view is the content view — we need the window.
573→                // Get the window from the view.
574→                let ns_view = handle.ns_view.as_ptr() as *mut c_void;
575→                let ns_window: *mut c_void =
576→                    unsafe { msg_send![ns_view as *mut AnyObject, window] };
577→                Ok(ns_window)
578→            }
579→            _ => Err("Expected AppKit window handle on macOS".into()),
580→        }
581→    }
582→
583→    #[cfg(not(target_os = "macos"))]
584→    {
585→        let _ = window;
586→        Err("NSView overlay is only supported on macOS".into())
587→    }
588→}
