538→fn decode_clipboard_text(
539→    content: *const GhosttyClipboardContent,
540→    content_len: usize,
541→) -> Option<String> {
542→    if content.is_null() || content_len == 0 {
543→        return None;
544→    }
545→
546→    let chunks = unsafe { std::slice::from_raw_parts(content, content_len) };
547→    let total_len = chunks.iter().map(|chunk| chunk.len).sum();
548→    let mut bytes = Vec::with_capacity(total_len);
549→
550→    for chunk in chunks {
551→        if chunk.data.is_null() || chunk.len == 0 {
552→            continue;
553→        }
554→
555→        let part = unsafe { std::slice::from_raw_parts(chunk.data as *const u8, chunk.len) };
556→        bytes.extend_from_slice(part);
557→    }
558→
559→    String::from_utf8(bytes).ok()
560→}
