108→fn unshifted_codepoint_from_event(event: &NSEvent) -> u32 {
109→    event
110→        .charactersIgnoringModifiers()
111→        .or_else(|| event.characters())
112→        .and_then(|text| text.to_string().chars().next())
113→        .map(|ch| ch as u32)
114→        .unwrap_or(0)
115→}
