117→fn matches_command_shortcut(event: &NSEvent, key: char) -> bool {
118→    let flags = event.modifierFlags();
119→    if !flags.contains(NSEventModifierFlags::Command) {
120→        return false;
121→    }
122→    if flags.contains(NSEventModifierFlags::Control) || flags.contains(NSEventModifierFlags::Option)
123→    {
124→        return false;
125→    }
126→
127→    event
128→        .charactersIgnoringModifiers()
129→        .map(|text| text.to_string())
130→        .map(|text| text.eq_ignore_ascii_case(&key.to_string()))
131→        .unwrap_or(false)
132→}
