445→/// Manages a native NSView overlay positioned on top of the Tauri webview.
446→/// Ghostty renders into this view via its own Metal infrastructure.
447→pub struct GhosttyOverlay {
448→    /// The NSView that contains the Metal layer. libghostty renders into this.
449→    view: Retained<GhosttyHostView>,
450→    /// Track visibility so we avoid redundant show/hide calls.
451→    visible: bool,
452→}
453→
454→// SAFETY: NSView operations are dispatched on the main thread via objc2.
455→// The overlay is only mutated through Mutex<GhosttyState>.
456→unsafe impl Send for GhosttyOverlay {}
457→unsafe impl Sync for GhosttyOverlay {}
458→
459→impl GhosttyOverlay {
460→    /// Create a new overlay NSView and add it as a subview of the given window.
461→    ///
462→    /// # Safety
463→    /// Must be called on the main thread. `window` must be a valid NSWindow pointer.
464→    pub unsafe fn new(window: *mut c_void) -> Result<Self, String> {
465→        // We must be on the main thread to create NSView
466→        let mtm = MainThreadMarker::new()
467→            .ok_or_else(|| "Must be called on the main thread".to_string())?;
468→
469→        let window: &NSWindow = unsafe { &*(window as *const NSWindow) };
470→        let content_view = window
471→            .contentView()
472→            .ok_or_else(|| "Window has no contentView".to_string())?;
473→
474→        // Create the overlay NSView
475→        let frame = content_view.frame();
476→        let view = GhosttyHostView::new(mtm, frame);
477→
478→        // Enable layer-backing (required for ghostty's Metal rendering)
479→        // but do NOT pre-create a CAMetalLayer — ghostty sets up its own
480→        // rendering infrastructure on the view internally.
481→        view.setWantsLayer(true);
482→
483→        // Add as subview — on top of the webview content
484→        content_view.addSubview(&view);
485→
486→        // Start hidden until explicitly shown
487→        view.setHidden(true);
488→
489→        Ok(Self {
490→            view,
491→            visible: false,
492→        })
493→    }
494→
495→    /// Returns the raw NSView pointer for passing to libghostty's surface config.
496→    pub fn nsview_ptr(&self) -> *mut c_void {
497→        let view_ref: &NSView = &self.view;
498→        view_ref as *const NSView as *mut c_void
499→    }
500→
501→    pub fn set_surface(&self, surface: *mut c_void) {
502→        self.view.set_surface(surface);
503→    }
504→
505→    pub fn clear_surface(&self) {
506→        self.view.clear_surface();
507→    }
508→
509→    /// Reposition and resize the overlay to match the terminal panel in the webview.
510→    ///
511→    /// Coordinates come from the frontend (top-left origin, CSS pixels).
512→    /// macOS NSView uses bottom-left origin, so we flip Y.
513→    pub fn update_frame(&self, x: f64, y: f64, width: f64, height: f64) {
514→        if let Some(superview) = unsafe { self.view.superview() } {
515→            let parent_height = superview.frame().size.height;
516→            // Convert from top-left (web) to bottom-left (macOS) origin
517→            let flipped_y = parent_height - y - height;
518→
519→            let frame = objc2_foundation::NSRect::new(
520→                objc2_foundation::NSPoint::new(x, flipped_y),
521→                objc2_foundation::NSSize::new(width, height),
522→            );
523→            self.view.setFrame(frame);
524→        }
525→    }
526→
527→    /// Show or hide the overlay.
528→    pub fn set_visible(&mut self, visible: bool) {
529→        if self.visible != visible {
530→            self.view.setHidden(!visible);
531→            self.visible = visible;
532→        }
533→    }
534→
535→    /// Whether the overlay is currently visible.
536→    #[allow(dead_code)]
537→    pub fn is_visible(&self) -> bool {
538→        self.visible
539→    }
540→
541→    /// Make the overlay the first responder (receive keyboard input).
542→    pub fn focus(&self) -> bool {
543→        unsafe {
544→            if let Some(window) = self.view.window() {
545→                let result: bool = msg_send![&*window, makeFirstResponder: &*self.view];
546→                return result;
547→            }
548→        }
549→        false
550→    }
551→}
