 11→fn debug_log(msg: &str) {
 12→    use std::io::Write;
 13→
 14→    let timestamp = std::time::SystemTime::now()
 15→        .duration_since(std::time::UNIX_EPOCH)
 16→        .unwrap_or_default();
 17→    let line = format!(
 18→        "[{}.{:03}] {}\n",
 19→        timestamp.as_secs(),
 20→        timestamp.subsec_millis(),
 21→        msg
 22→    );
 23→    if let Ok(mut f) = std::fs::OpenOptions::new()
 24→        .create(true)
 25→        .append(true)
 26→        .open("/tmp/entire-terminal-debug.log")
 27→    {
 28→        let _ = f.write_all(line.as_bytes());
 29→    }
 30→}
