387→        config.userdata = ptr::null_mut();
388→        config.scale_factor = scale_factor;
389→        config.font_size = 0.0; // 0 = use config default
390→        config.working_directory = wd_ptr;
391→        config.command = cmd_ptr;
392→        config.env_vars = ptr::null_mut();
393→        config.env_var_count = 0;
394→        config.initial_input = ptr::null();
395→        config.wait_after_command = false;
396→        config.context = GhosttySurfaceContext::Split;
397→
398→        // Debug: log config struct details
399→        {
400→            use std::io::Write;
401→            let ts = std::time::SystemTime::now()
402→                .duration_since(std::time::UNIX_EPOCH)
403→                .unwrap_or_default();
404→            let msg = format!(
405→                "[{}.{:03}] GhosttySurface::new config: app_ptr={:?}, nsview={:?}, \
406→                 scale_factor={}, font_size={}, working_dir_ptr={:?}, cmd_ptr={:?}, \
407→                 env_var_count={}, wait_after_command={}, context={:?}, \
408→                 struct size={}, struct align={}\n",
409→                ts.as_secs(),
410→                ts.subsec_millis(),
411→                app.raw(),
412→                nsview,
413→                scale_factor,
414→                config.font_size,
415→                config.working_directory,
416→                config.command,
417→                config.env_var_count,
418→                config.wait_after_command,
419→                config.context as u32,
420→                std::mem::size_of::<GhosttySurfaceConfig>(),
421→                std::mem::align_of::<GhosttySurfaceConfig>(),
422→            );
423→            if let Ok(mut f) = std::fs::OpenOptions::new()
424→                .create(true)
425→                .append(true)
426→                .open("/tmp/entire-terminal-debug.log")
427→            {
428→                let _ = f.write_all(msg.as_bytes());
429→            }
430→        }
431→
432→        let surface = unsafe { ghostty_surface_new(app.raw(), &config) };
433→        if surface.is_null() {
434→            return Err("ghostty_surface_new returned null".into());
435→        }
436→
437→        Ok(Self {
438→            inner: surface,
439→            _working_dir: working_dir_c,
440→            _command: command_c,
441→        })
442→    }
