569→fn write_system_clipboard_text(text: &str) -> bool {
570→    let pasteboard = NSPasteboard::generalPasteboard();
571→    pasteboard.clearContents();
572→    let text = NSString::from_str(text);
573→    pasteboard.setString_forType(&text, unsafe { NSPasteboardTypeString })
574→}
