use objc2_app_kit::{NSPasteboard, NSPasteboardTypeString};
use objc2_foundation::NSString;
use std::ffi::{c_char, c_void, CString};
use std::ops::{BitOr, BitOrAssign};
use std::ptr;
use std::sync::{Arc, Mutex};

fn debug_log(msg: &str) {
    use std::io::Write;

    let timestamp = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default();
    let line = format!(
        "[{}.{:03}] {}\n",
        timestamp.as_secs(),
        timestamp.subsec_millis(),
        msg
    );
    if let Ok(mut f) = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open("/tmp/entire-terminal-debug.log")
    {
        let _ = f.write_all(line.as_bytes());
    }
}

// ---------------------------------------------------------------------------
// FFI declarations for the current libghostty embedding ABI.
//
// NOTE: the vendored `vendor/ghostty/ghostty.h` in this repo is stale for the
// surface embedding path. Keep these definitions aligned with the actual
// library binary we ship.
// ---------------------------------------------------------------------------

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyPlatform {
    Invalid = 0,
    MacOS = 1,
    IOS = 2,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyClipboard {
    Standard = 0,
    Selection = 1,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyClipboardRequest {
    Paste = 0,
    Osc52Read = 1,
    Osc52Write = 2,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyMouseState {
    Release = 0,
    Press = 1,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyMouseButton {
    Left = 0,
    Middle = 1,
    Right = 2,
    Four = 3,
    Five = 4,
    Six = 5,
    Seven = 6,
    Eight = 7,
    Nine = 8,
    Ten = 9,
    Eleven = 10,
}

#[repr(transparent)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct GhosttyInputMods(pub u32);

impl GhosttyInputMods {
    pub const NONE: Self = Self(0);
    pub const SHIFT: Self = Self(1 << 0);
    pub const CTRL: Self = Self(1 << 1);
    pub const ALT: Self = Self(1 << 2);
    pub const SUPER: Self = Self(1 << 3);

    pub fn contains(self, other: Self) -> bool {
        (self.0 & other.0) == other.0
    }
}

impl BitOr for GhosttyInputMods {
    type Output = Self;

    fn bitor(self, rhs: Self) -> Self::Output {
        Self(self.0 | rhs.0)
    }
}

impl BitOrAssign for GhosttyInputMods {
    fn bitor_assign(&mut self, rhs: Self) {
        self.0 |= rhs.0;
    }
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttyInputAction {
    Release = 0,
    Press = 1,
    Repeat = 2,
}

#[repr(C)]
#[derive(Debug, Clone, Copy)]
#[allow(dead_code)]
pub enum GhosttySurfaceContext {
    Window = 0,
    Tab = 1,
    Split = 2,
}

#[repr(C)]
pub struct GhosttyEnvVar {
    pub key: *const c_char,
    pub value: *const c_char,
}

#[repr(C)]
pub struct GhosttyClipboardContent {
