286→/// Global Ghostty application instance. One per process.
287→pub struct GhosttyApp {
288→    inner: *mut c_void,
289→}
290→
291→// SAFETY: GhosttyApp is only accessed through Mutex<GhosttyState>
292→unsafe impl Send for GhosttyApp {}
293→unsafe impl Sync for GhosttyApp {}
294→
295→#[allow(dead_code)]
296→impl GhosttyApp {
297→    /// Initialize libghostty and create the app with the user's default config.
298→    pub fn new() -> Result<Self, String> {
299→        unsafe {
300→            // Initialize the library
301→            let ret = ghostty_init(0, ptr::null_mut());
302→            if ret != 0 {
303→                return Err(format!("ghostty_init failed with code {}", ret));
304→            }
305→
306→            // Create and load config (reads ~/.config/ghostty/config automatically)
307→            let config = ghostty_config_new();
308→            if config.is_null() {
309→                return Err("ghostty_config_new returned null".into());
310→            }
311→            ghostty_config_load_default_files(config);
312→            ghostty_config_finalize(config);
313→
314→            // Set up runtime callbacks
315→            let runtime_config = GhosttyRuntimeConfig {
316→                userdata: ptr::null_mut(),
317→                supports_selection_clipboard: true,
318→                wakeup_cb: runtime_wakeup,
319→                action_cb: runtime_action,
320→                read_clipboard_cb: runtime_read_clipboard,
321→                confirm_read_clipboard_cb: runtime_confirm_read_clipboard,
322→                write_clipboard_cb: runtime_write_clipboard,
323→                close_surface_cb: runtime_close_surface,
324→            };
325→
326→            let app = ghostty_app_new(&runtime_config, config);
327→            if app.is_null() {
328→                ghostty_config_free(config);
329→                return Err("ghostty_app_new returned null".into());
330→            }
331→
332→            Ok(Self { inner: app })
333→        }
334→    }
335→
336→    /// Pump the ghostty event loop. Call from a timer or run loop.
337→    pub fn tick(&self) {
338→        unsafe { ghostty_app_tick(self.inner) }
339→    }
340→
341→    pub fn set_focus(&self, focused: bool) {
342→        unsafe { ghostty_app_set_focus(self.inner, focused) }
343→    }
344→
345→    pub fn raw(&self) -> *mut c_void {
346→        self.inner
347→    }
348→}
349→
350→impl Drop for GhosttyApp {
351→    fn drop(&mut self) {
352→        if !self.inner.is_null() {
353→            unsafe { ghostty_app_free(self.inner) };
354→        }
355→    }
356→}
