358→/// A terminal surface backed by libghostty. Renders to a Metal layer.
359→pub struct GhosttySurface {
360→    inner: *mut c_void,
361→    // Keep CStrings alive for the lifetime of the surface
362→    _working_dir: Option<CString>,
363→    _command: Option<CString>,
364→}
