369→#[allow(dead_code)]
370→impl GhosttySurface {
371→    /// Create a new surface attached to the given NSView.
372→    pub fn new(
373→        app: &GhosttyApp,
374→        nsview: *mut c_void,
375→        working_dir: Option<&str>,
376→        command: Option<&str>,
377→        scale_factor: f64,
378→    ) -> Result<Self, String> {
379→        let working_dir_c = working_dir.map(|s| CString::new(s).unwrap());
380→        let command_c = command.map(|s| CString::new(s).unwrap());
381→
382→        let wd_ptr = working_dir_c.as_ref().map_or(ptr::null(), |s| s.as_ptr());
383→        let cmd_ptr = command_c.as_ref().map_or(ptr::null(), |s| s.as_ptr());
384→
385→        let mut config = unsafe { ghostty_surface_config_new() };
386→        config.platform_tag = GhosttyPlatform::MacOS;
387→        config.platform = GhosttyPlatformUnion { nsview };
388→        config.userdata = ptr::null_mut();
389→        config.scale_factor = scale_factor;
390→        config.font_size = 0.0; // 0 = use config default
391→        config.working_directory = wd_ptr;
392→        config.command = cmd_ptr;
393→        config.env_vars = ptr::null_mut();
394→        config.env_var_count = 0;
395→        config.initial_input = ptr::null();
396→        config.wait_after_command = false;
397→        config.context = GhosttySurfaceContext::Split;
398→
399→        // Debug: log config struct details
400→        {
401→            use std::io::Write;
402→            let ts = std::time::SystemTime::now()
403→                .duration_since(std::time::UNIX_EPOCH)
404→                .unwrap_or_default();
405→            let msg = format!(
406→                "[{}.{:03}] GhosttySurface::new config: app_ptr={:?}, nsview={:?}, \
407→                 scale_factor={}, font_size={}, working_dir_ptr={:?}, cmd_ptr={:?}, \
408→                 env_var_count={}, wait_after_command={}, context={:?}, \
409→                 struct size={}, struct align={}\n",
410→                ts.as_secs(),
411→                ts.subsec_millis(),
412→                app.raw(),
413→                nsview,
414→                scale_factor,
415→                config.font_size,
416→                config.working_directory,
417→                config.command,
418→                config.env_var_count,
419→                config.wait_after_command,
420→                config.context as u32,
421→                std::mem::size_of::<GhosttySurfaceConfig>(),
422→                std::mem::align_of::<GhosttySurfaceConfig>(),
423→            );
424→            if let Ok(mut f) = std::fs::OpenOptions::new()
425→                .create(true)
426→                .append(true)
427→                .open("/tmp/entire-terminal-debug.log")
428→            {
429→                let _ = f.write_all(msg.as_bytes());
430→            }
431→        }
432→
433→        let surface = unsafe { ghostty_surface_new(app.raw(), &config) };
434→        if surface.is_null() {
435→            return Err("ghostty_surface_new returned null".into());
436→        }
437→
438→        Ok(Self {
439→            inner: surface,
440→            _working_dir: working_dir_c,
441→            _command: command_c,
442→        })
443→    }
