539→fn decode_clipboard_text(
540→    content: *const GhosttyClipboardContent,
541→    content_len: usize,
542→) -> Option<String> {
543→    if content.is_null() || content_len == 0 {
544→        return None;
545→    }
546→
547→    let chunks = unsafe { std::slice::from_raw_parts(content, content_len) };
548→    let total_len = chunks.iter().map(|chunk| chunk.len).sum();
549→    let mut bytes = Vec::with_capacity(total_len);
550→
551→    for chunk in chunks {
552→        if chunk.data.is_null() || chunk.len == 0 {
553→            continue;
554→        }
555→
556→        let part = unsafe { std::slice::from_raw_parts(chunk.data as *const u8, chunk.len) };
557→        bytes.extend_from_slice(part);
558→    }
559→
560→    String::from_utf8(bytes).ok()
561→}
