563→pub(super) fn system_clipboard_text() -> Option<String> {
564→    let pasteboard = NSPasteboard::generalPasteboard();
565→    pasteboard
566→        .stringForType(unsafe { NSPasteboardTypeString })
567→        .map(|text| text.to_string())
568→}
