570→fn write_system_clipboard_text(text: &str) -> bool {
571→    let pasteboard = NSPasteboard::generalPasteboard();
572→    pasteboard.clearContents();
573→    let text = NSString::from_str(text);
574→    pasteboard.setString_forType(&text, unsafe { NSPasteboardTypeString })
575→}
