178→/// Show or hide the native overlay (for terminal panel toggle).
179→#[tauri::command]
180→pub fn ghostty_show_overlay(
181→    surface_id: String,
182→    visible: bool,
183→    state: State<'_, Mutex<super::GhosttyState>>,
184→) -> Result<(), String> {
185→    let mut gs = state.lock().map_err(|_| "State lock error".to_string())?;
186→    if visible {
187→        if let Some(app) = gs.app.as_ref() {
188→            app.set_focus(true);
189→            debug_log("ghostty_show_overlay: app focus set true");
190→        }
191→    }
192→    let entry = gs
193→        .surfaces
194→        .get_mut(&surface_id)
195→        .ok_or_else(|| format!("Surface not found: {}", surface_id))?;
196→
197→    entry.overlay.set_visible(visible);
198→    if visible {
199→        let focused = entry.overlay.focus();
200→        debug_log(&format!(
201→            "ghostty_show_overlay: makeFirstResponder result={}",
202→            focused
203→        ));
204→        entry.surface.set_focus(true);
205→    } else {
206→        entry.surface.set_focus(false);
207→    }
208→    Ok(())
209→}
