let chunks = unsafe { std::slice::from_raw_parts(content, content_len) };

// Ghostty sends multiple representations (text/plain, text/html, etc.).
// Use only the plain text chunk for the system clipboard.
for chunk in chunks {
    if chunk.data.is_null() || chunk.mime.is_null() {
        continue;
    }
    let mime = unsafe { std::ffi::CStr::from_ptr(chunk.mime) };
    if mime.to_bytes() == b"text/plain" {
        let cstr = unsafe { std::ffi::CStr::from_ptr(chunk.data) };
        return String::from_utf8(cstr.to_bytes().to_vec()).ok();
    }
}

// Fallback: use the first chunk with data if no text/plain found
for chunk in chunks {
    if chunk.data.is_null() {
        continue;
    }
    let cstr = unsafe { std::ffi::CStr::from_ptr(chunk.data) };
    return String::from_utf8(cstr.to_bytes().to_vec()).ok();
}

