/// Global Ghostty application instance. One per process.
pub struct GhosttyApp {
    inner: *mut c_void,
}

// SAFETY: GhosttyApp is only accessed through Mutex<GhosttyState>
unsafe impl Send for GhosttyApp {}
unsafe impl Sync for GhosttyApp {}

#[allow(dead_code)]
impl GhosttyApp {
    /// Initialize libghostty and create the app with the user's default config.
    pub fn new() -> Result<Self, String> {
        unsafe {
            // Initialize the library
            let ret = ghostty_init(0, ptr::null_mut());
            if ret != 0 {
                return Err(format!("ghostty_init failed with code {}", ret));
            }

            // Create and load config (reads ~/.config/ghostty/config automatically)
            let config = ghostty_config_new();
            if config.is_null() {
                return Err("ghostty_config_new returned null".into());
            }
            ghostty_config_load_default_files(config);
            ghostty_config_finalize(config);

            // Set up runtime callbacks
            let runtime_config = GhosttyRuntimeConfig {
                userdata: ptr::null_mut(),
                supports_selection_clipboard: true,
                wakeup_cb: runtime_wakeup,
                action_cb: runtime_action,
                read_clipboard_cb: runtime_read_clipboard,
                confirm_read_clipboard_cb: runtime_confirm_read_clipboard,
                write_clipboard_cb: runtime_write_clipboard,
                close_surface_cb: runtime_close_surface,
            };

            let app = ghostty_app_new(&runtime_config, config);
            if app.is_null() {
                ghostty_config_free(config);
                return Err("ghostty_app_new returned null".into());
            }

            Ok(Self { inner: app })
        }
    }

    /// Pump the ghostty event loop. Call from a timer or run loop.
    pub fn tick(&self) {
        unsafe { ghostty_app_tick(self.inner) }
    }

    pub fn set_focus(&self, focused: bool) {
        unsafe { ghostty_app_set_focus(self.inner, focused) }
    }

    pub fn raw(&self) -> *mut c_void {
        self.inner
    }
}

impl Drop for GhosttyApp {
    fn drop(&mut self) {
        if !self.inner.is_null() {
            unsafe { ghostty_app_free(self.inner) };
        }
    }
}

